import boto3
import json

def process_message(message_body):
    # Example of dynamic message processing
    message = json.loads(message_body)
    if 'action' in message:
        action = message['action']
        if action == 'process_data':
            process_data(message.get('data'))
        elif action == 'send_email':
            send_email(message.get('email_details'))
        else:
            print(f"Unknown action: {action}")
    else:
        print("No action specified in the message")

def process_data(data):
    # Implement data processing logic here
    print(f"Processing data: {data}")

def send_email(email_details):
    # Implement email sending logic here
    print(f"Sending email to: {email_details.get('to')} with subject: {email_details.get('subject')}")

def main():
    sqs = boto3.client('sqs')
    queue_url = 'your_sqs_queue_url'  # Replace with your SQS queue URL

    while True:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )

        if 'Messages' in response:
            for message in response['Messages']:
                process_message(message['Body'])
                # Delete the message from the queue after processing
                sqs.delete_message(
                    QueueUrl=queue_url,
                    ReceiptHandle=message['ReceiptHandle']
                )

if __name__ == '__main__':
    main()